 1→{
 2→  "name": "mt-tool-web",
 3→  "private": true,
 4→  "version": "1.0.0",
 5→  "type": "module",
 6→  "scripts": {
 7→    "dev": "vite",
 8→    "build": "vite build",
 9→    "preview": "vite preview"
10→  },
11→  "devDependencies": {
12→    "vite": "^6.3.2"
13→  }
14→}
15→

 1→server {
 2→    listen 80;
 3→    server_name _;
 4→
 5→    root /usr/share/nginx/html;
 6→    index index.html;
 7→
 8→    client_max_body_size 100m;
 9→
10→    # gzip 压缩
11→    gzip on;
12→    gzip_min_length 1k;
13→    gzip_comp_level 5;
14→    gzip_types text/plain text/css application/json application/javascript text/xml application/xml application/xml+rss text/javascript image/svg+xml;
15→    gzip_vary on;
16→    gzip_static on;
17→
18→    # 静态资源缓存（Vite 构建产物自带 hash）
19→    location /assets/ {
20→        expires 1y;
21→        add_header Cache-Control "public, immutable";
22→    }
23→
24→    # API 反向代理到后端 Service
25→    location /api/ {
26→        proxy_pass http://mt-tool-server:18081;
27→        proxy_set_header Host $host;
28→        proxy_set_header X-Real-IP $remote_addr;
29→        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
30→        proxy_set_header X-Forwarded-Proto $scheme;
31→
32→        proxy_connect_timeout 10s;
33→        proxy_read_timeout 60s;
34→        proxy_send_timeout 30s;
35→    }
36→
37→    # 独立页面：login / callback 必须精确匹配，不走 SPA fallback
38→    location = /login.html {
39→        try_files /login.html =404;
40→    }
41→
42→    # OAuth2 回调页面
43→    location /oauth/callback {
44→        try_files /callback.html =404;
45→    }
46→
47→    # SPA 路由 fallback
48→    location / {
49→        try_files $uri $uri/ /index.html;
50→    }
51→}
